import{_ as e,o as a,c as i,a0 as o}from"./chunks/framework.NWv86GGy.js";const u=JSON.parse('{"title":"South Africa — Country Brief","description":"Trans relocation guide for South Africa: legal overview, visa options, cost of living, and key considerations.","frontmatter":{"layout":"doc","title":"South Africa — Country Brief","description":"Trans relocation guide for South Africa: legal overview, visa options, cost of living, and key considerations."},"headers":[],"relativePath":"countries/south-africa/index.md","filePath":"countries/south-africa/index.md","lastUpdated":1780601195000}'),r={name:"countries/south-africa/index.md"};function n(s,t,l,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="🇿🇦-south-africa" tabindex="-1"><span style="color:#007a4d;">🇿🇦 South Africa</span> <a class="header-anchor" href="#🇿🇦-south-africa" aria-label="Permalink to &quot;&lt;span style=&quot;color: #007a4d;&quot;&gt;🇿🇦 South Africa&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Pretoria (administrative), Cape Town (legislative)</td></tr><tr><td><strong>Language</strong></td><td>11 official languages (English widely spoken)</td></tr><tr><td><strong>Currency</strong></td><td>South African Rand (ZAR)</td></tr><tr><td><strong>Equaldex Score</strong></td><td>58</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>2/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><ul><li><strong>Gender Recognition:</strong> Medicalised. The Alteration of Sex Description and Sex Status Act (2003) requires surgery or a court order for gender marker change.</li><li><strong>Anti-Discrimination Law:</strong> Constitutional protections since 1996. The Equality Act (Promotion of Equality and Prevention of Unfair Discrimination Act, 2000) explicitly includes gender identity.</li><li><strong>Hate Crime Laws:</strong> None specific to gender identity. General criminal law applies.</li><li><strong>Same-Sex Marriage:</strong> Legal since 2006 (Civil Union Act).</li></ul><h2 id="healthcare" tabindex="-1">Healthcare <a class="header-anchor" href="#healthcare" aria-label="Permalink to &quot;Healthcare&quot;">​</a></h2><ul><li><strong>HRT Access:</strong> Limited public. Private informed consent available in major cities (Cape Town, Johannesburg).</li><li><strong>Cost:</strong> ZAR 200–800/month public (≈ €10–40). Private: ZAR 500–1,500/month (≈ €25–75).</li></ul><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Income Req.</th><th>Processing</th><th>Leads to PR?</th></tr></thead><tbody><tr><td>Digital Nomad Visa (2024)</td><td>ZAR 1 million/year (≈ €52,000)</td><td>2–4 months</td><td>No</td></tr><tr><td>Work Visa</td><td>Job offer</td><td>2–6 months</td><td>Yes</td></tr><tr><td>Critical Skills Visa</td><td>Listed profession</td><td>4–8 months</td><td>Yes</td></tr></tbody></table><h2 id="cost-of-living-cape-town" tabindex="-1">Cost of Living (Cape Town) <a class="header-anchor" href="#cost-of-living-cape-town" aria-label="Permalink to &quot;Cost of Living (Cape Town)&quot;">​</a></h2><p>1-bedroom: ZAR 8,000–15,000/month (≈ €420–780). Monthly budget: ZAR 18,000–35,000 (≈ €950–1,800).</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><strong>⚠️ Extreme violence risk</strong> — South Africa has one of the highest murder rates in the world. Trans women, especially Black trans women, face disproportionately high violence rates.</li><li><strong>Constitutional protections</strong> are strong but enforcement is weak</li><li><strong>Private healthcare</strong> is good; public is poor</li><li><strong>Safety varies enormously</strong> by neighbourhood</li><li><strong>Not recommended</strong> for most trans migrants unless you have strong local connections and a high safety budget</li><li><strong>Asylum:</strong> Available in principle but limited in practice</li></ul><p><em>Sources: Iranti, ILGA, Equaldex. Last verified: June 2026.</em></p>',13)])])}const f=e(r,[["render",n]]);export{u as __pageData,f as default};
